import React, { useState, useEffect } from 'react';
import { auth, db } from '../pages/Firebase';
import { collection, addDoc, getDocs, query, orderBy, serverTimestamp } from 'firebase/firestore';
import './Discussion.css';

const Discussion = ({ pageId, title }) => {
  const [posts, setPosts] = useState([]);
  const [newPost, setNewPost] = useState('');
  const [replies, setReplies] = useState({});
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchPosts();
  }, [pageId, fetchPosts]);

  const fetchPosts = React.useCallback(async () => {
    try {
      const postsQuery = query(
        collection(db, 'forum', pageId, 'posts'),
        orderBy('timestamp', 'desc')
      );
      const postsSnapshot = await getDocs(postsQuery);
      const postsData = postsSnapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      }));
      setPosts(postsData);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching posts:', error);
      setLoading(false);
    }
  }, [pageId]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!auth.currentUser) {
      alert('Please log in to post');
      return;
    }

    try {
      const postData = {
        content: newPost,
        author: auth.currentUser.displayName || auth.currentUser.email,
        userId: auth.currentUser.uid,
        timestamp: serverTimestamp()
      };

      await addDoc(collection(db, 'forum', pageId, 'posts'), postData);
      setNewPost('');
      fetchPosts();
    } catch (error) {
      console.error('Error adding post:', error);
    }
  };

  const handleReply = async (postId, replyContent) => {
    if (!auth.currentUser) {
      alert('Please log in to reply');
      return;
    }

    try {
      const replyData = {
        content: replyContent,
        author: auth.currentUser.displayName || auth.currentUser.email,
        userId: auth.currentUser.uid,
        timestamp: serverTimestamp()
      };

      await addDoc(collection(db, 'forum', pageId, 'posts', postId, 'replies'), replyData);
      setReplies(prev => ({
        ...prev,
        [postId]: [...(prev[postId] || []), replyData]
      }));
    } catch (error) {
      console.error('Error adding reply:', error);
    }
  };

  if (loading) {
    return <div className="discussion-loading">Loading discussion...</div>;
  }

  return (
    <div className="discussion-container">
      <h2>{title} Discussion</h2>
      {auth.currentUser ? (
        <form onSubmit={handleSubmit} className="discussion-form">
          <textarea
            value={newPost}
            onChange={(e) => setNewPost(e.target.value)}
            placeholder="Share your thoughts..."
            required
          />
          <button type="submit">Post</button>
        </form>
      ) : (
        <p className="login-prompt">Please log in to participate in the discussion</p>
      )}
      
      <div className="posts-container">
        {posts.map(post => (
          <div key={post.id} className="post-card">
            <div className="post-content">
              <p>{post.content}</p>
              <div className="post-meta">
                <span>By {post.author}</span>
                <span>{new Date(post.timestamp?.toDate()).toLocaleDateString()}</span>
              </div>
            </div>
            <div className="replies-section">
              {replies[post.id]?.map((reply, index) => (
                <div key={index} className="reply">
                  <p>{reply.content}</p>
                  <div className="reply-meta">
                    <span>By {reply.author}</span>
                    <span>{new Date(reply.timestamp?.toDate()).toLocaleDateString()}</span>
                  </div>
                </div>
              ))}
              {auth.currentUser && (
                <form onSubmit={(e) => {
                  e.preventDefault();
                  const replyContent = e.target.reply.value;
                  handleReply(post.id, replyContent);
                  e.target.reply.value = '';
                }}>
                  <input
                    type="text"
                    name="reply"
                    placeholder="Write a reply..."
                    required
                  />
                  <button type="submit">Reply</button>
                </form>
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Discussion;
